import json
import re

file_path = locals()['var_functions.query_db:14']
with open(file_path, 'r') as f:
    businesses = json.load(f)

print('Total businesses:', len(businesses))

def extract_cats(desc):
    if not desc:
        return []
    cats = []
    desc_lower = desc.lower()

    if 'services in' in desc_lower:
        parts = desc.split('services in')
        if len(parts) > 1:
            cat_text = parts[1].split('.')[0]
            for item in cat_text.split(','):
                item = item.strip().strip('"\'').rstrip('.')
                if item and ' and ' not in item:
                    cats.append(item)
                elif ' and ' in item:
                    subitems = item.split(' and ')
                    for sub in subitems:
                        sub = sub.strip().strip('"\'').rstrip('.')
                        if sub:
                            cats.append(sub)

    if not cats and 'including' in desc_lower:
        parts = desc.split('including')
        if len(parts) > 1:
            cat_text = parts[1].split('.')[0]
            for item in cat_text.split(','):
                item = item.strip().strip('"\'').rstrip('.')
                if item and ' and ' not in item:
                    cats.append(item)
                elif ' and ' in item:
                    subitems = item.split(' and ')
                    for sub in subitems:
                        sub = sub.strip().strip('"\'').rstrip('.')
                        if sub:
                            cats.append(sub)

    return list(set([c for c in cats if c and len(c) < 80]))

cat_counts = {}
for b in businesses:
    desc = b.get('description', '')
    cats = extract_cats(desc)
    for cat in cats:
        cat_counts[cat] = cat_counts.get(cat, 0) + 1

top_cats = sorted(cat_counts.items(), key=lambda x: x[1], reverse=True)[:15]

print('\nTop 15 categories:')
for cat, count in top_cats:
    print(cat + ': ' + str(count))

result = {
    'total': len(businesses),
    'top_categories': top_cats,
    'category_counts': cat_counts
}

print('__RESULT__:')
print(json.dumps(result))

