import json
import re

file_path = locals()['var_functions.query_db:14']
with open(file_path, 'r') as f:
    businesses = json.load(f)

print('Total businesses with credit cards:', len(businesses))

# Extract categories for all businesses
def extract_categories(desc):
    if not desc:
        return []

    cats = []
    desc_lower = desc.lower()

    # Various patterns to try
    patterns = [
        (r'services in ([^\.]+)', 1),
        (r'including ([^\.]+)', 1),
        (r'categories of ([^\.]+)', 1),
        (r'fields of ([^\.]+)', 1),
        (r'category of [\'"]?([^\'"\.]+)', 1),
        (r'specializes? in ([^\.]+)', 1),
    ]

    successful = False
    for pattern, group in patterns:
        import re
        match = re.search(pattern, desc_lower)
        if match:
            text = match.group(group)
            # Split by comma or 'and'
            items = re.split(r',|\band\b', text)
            for item in items:
                item = item.strip().strip('"\'').rstrip('.')
                if item and len(item) < 80 and item != 'a range':
                    cats.append(item.title())
            if cats:
                successful = True
                break

    # Fallback for known patterns
    if not successful:
        if 'restaurant' in desc_lower:
            cats.append('Restaurants')
        if 'salon' in desc_lower:
            if 'hair' in desc_lower:
                cats.append('Hair Salons')
            elif 'nail' in desc_lower:
                cats.append('Nail Salons')

    return list(set([c for c in cats if c]))

# Process all businesses and count by category
category_businesses = {}
business_category_map = {}

for b in businesses:
    business_id = b['business_id']
    desc = b.get('description', '')
    categories = extract_categories(desc)

    business_category_map[business_id] = categories

    for cat in categories:
        if cat not in category_businesses:
            category_businesses[cat] = []
        category_businesses[cat].append(business_id)

top_categories = sorted(category_businesses.items(), key=lambda x: len(x[1]), reverse=True)[:15]

print('\nTop 15 categories by business count:')
for i, (cat, biz_ids) in enumerate(top_categories, 1):
    print(f'{i}. {cat}: {len(biz_ids)} businesses')

# Save results for next step
result = {
    'total_businesses': len(businesses),
    'category_businesses': category_businesses,
    'business_category_map': business_category_map,
    'top_categories': top_categories
}

print('__RESULT__:')
print(json.dumps(result))

