import json
import re

# Load the data
file_path = locals()['var_functions.query_db:14']
with open(file_path, 'r') as f:
    businesses = json.load(f)

# Extract categories function
def get_categories(description):
    if not description:
        return []

    cats = []
    desc = description.lower()

    # Try to find service categories
    if 'services in' in desc:
        section = desc.split('services in')[1].split('.')[0]
        items = [item.strip() for item in section.split(',')]
        for item in items:
            if item and len(item) < 80:
                cats.append(item.title())
    elif 'including' in desc:
        section = desc.split('including')[1].split('.')[0]
        items = [item.strip() for item in section.split(',')]
        for item in items:
            if item and len(item) < 80:
                cats.append(item.title())

    # Clean up 'and' items
    cleaned_cats = []
    for cat in cats:
        if ' and ' in cat.lower():
            parts = cat.split(' and ')
            for part in parts:
                part = part.strip()
                if part:
                    cleaned_cats.append(part)
        else:
            cleaned_cats.append(cat)

    return list(set(cleaned_cats))

# Process all businesses
category_counts = {}
total_processed = 0

for b in businesses:
    desc = b.get('description', '')
    cats = get_categories(desc)

    if cats:
        total_processed += 1
        for cat in cats:
            category_counts[cat] = category_counts.get(cat, 0) + 1

# Get top categories
top_cats = sorted(category_counts.items(), key=lambda x: x[1], reverse=True)[:10]

output = {
    'total_credit_card_businesses': len(businesses),
    'businesses_with_categories': total_processed,
    'top_categories': top_cats,
    'all_category_counts': category_counts
}

print(total_processed, 'businesses had category information')
print('Top categories:', top_cats)

print('__RESULT__:')
